**Step 1**: 创建 DashboardIntegration 服务
```typescript
// src/dashboard/integration/dashboard-integration.ts

import { RealtimeService } from '../services/realtime.service'
import { IterationEventEmitter } from './iteration-event-emitter'
import { IterationState, AgentState } from '../types'

export class DashboardIntegration {
  private realtimeService: RealtimeService
  private eventEmitter: IterationEventEmitter

  constructor(realtimeService: RealtimeService) {
    this.realtimeService = realtimeService
    this.eventEmitter = new IterationEventEmitter()
    this.setupEventListeners()
  }

  private setupEventListeners(): void {
    // 监听迭代开始事件
    this.eventEmitter.on('iteration.start', async (iteration: IterationState) => {
      await this.realtimeService.broadcast('iteration.started', {
        iterationNumber: iteration.iterationNumber,
        requirement: iteration.requirement,
        timestamp: Date.now()
      })
    })

    // 监听 Agent 状态变化事件
    this.eventEmitter.on('agent.status_change', async (agent: AgentState) => {
      await this.realtimeService.broadcast('agent.status_changed', {
        name: agent.name,
        status: agent.status,
        currentTask: agent.currentTask
      })
    })

    // 监听迭代进度事件
    this.eventEmitter.on('iteration.progress', async (data) => {
      await this.realtimeService.broadcast('iteration.progress', {
        progress: data.progress,
        message: data.message,
        timestamp: Date.now()
      })
    })

    // 监听迭代完成事件
    this.eventEmitter.on('iteration.complete', async (iteration: IterationState) => {
      await this.realtimeService.broadcast('iteration.completed', {
        iterationNumber: iteration.iterationNumber,
        status: iteration.status,
        duration: iteration.endTime! - iteration.startTime,
        timestamp: Date.now()
      })
    })
  }

  getEventEmitter(): IterationEventEmitter {
    return this.eventEmitter
  }
}
```

**Step 2**: 集成到 AutoIterationEngine
```typescript
// src/auto-iteration.ts

import { DashboardIntegration } from './dashboard/integration/dashboard-integration'
import { getServices } from './dashboard/server'

export class AutoIterationEngine {
  private dashboardIntegration?: DashboardIntegration

  async initialize(): Promise<void> {
    // 初始化 Dashboard 集成
    const { realtimeService } = getServices()
    this.dashboardIntegration = new DashboardIntegration(realtimeService)
  }

  async startIteration(requirement?: string): Promise<void> {
    const eventEmitter = this.dashboardIntegration?.getEventEmitter()

    // 迭代开始
    eventEmitter?.emit('iteration.start', this.state)

    // Agent 执行...
    for (const agent of this.agents) {
      // 更新 Agent 状态
      eventEmitter?.emit('agent.status_change', agent.getState())

      // 执行任务...
      await agent.execute(requirement)

      // 推送进度
      eventEmitter?.emit('iteration.progress', {
        progress: calculateProgress(),
        message: `${agent.name} 完成`
      })
    }

    // 迭代完成
    eventEmitter?.emit('iteration.complete', this.state)
  }
}
```

