#### ✅ P0-3: 完善 WebSocket 连接管理（1 天）

**核心任务**：
1. 实现自动重连机制
2. 实现心跳检测
3. 实现连接状态管理

**实现代码**：

```typescript
// dashboard/src/services/websocket.ts

export class WebSocketService {
  private ws: WebSocket | null = null
  private reconnectAttempts = 0
  private maxReconnectAttempts = 5
  private reconnectTimeout: NodeJS.Timeout | null = null
  private heartbeatInterval: NodeJS.Timeout | null = null
  private store = useWebSocketStore()

  connect(): void {
    if (this.ws?.readyState === WebSocket.OPEN) {
      return
    }

    this.store.setConnecting()
    this.ws = new WebSocket('ws://localhost:3000/api/ws')

    this.ws.onopen = () => {
      this.store.setConnected()
      this.reconnectAttempts = 0
      this.startHeartbeat()
    }

    this.ws.onclose = () => {
      this.store.setDisconnected()
      this.stopHeartbeat()
      this.attemptReconnect()
    }

    this.ws.onerror = (error) => {
      this.store.setError(`连接错误: ${error}`)
    }

    this.ws.onmessage = (event) => {
      this.handleMessage(event.data)
    }
  }

  private attemptReconnect(): void {
    if (this.reconnectAttempts >= this.maxReconnectAttempts) {
      this.store.setError('连接失败，已达到最大重连次数')
      return
    }

    this.reconnectAttempts++
    this.store.setReconnecting(this.reconnectAttempts)

    const delay = Math.min(1000 * Math.pow(2, this.reconnectAttempts), 30000)

    this.reconnectTimeout = setTimeout(() => {
      this.connect()
    }, delay)
  }

  private startHeartbeat(): void {
    this.heartbeatInterval = setInterval(() => {
      if (this.ws?.readyState === WebSocket.OPEN) {
        this.ws.send(JSON.stringify({ type: 'ping' }))
      }
    }, 30000)
  }

  private stopHeartbeat(): void {
    if (this.heartbeatInterval) {
      clearInterval(this.heartbeatInterval)
      this.heartbeatInterval = null
    }
  }

  disconnect(): void {
    this.stopHeartbeat()
    if (this.reconnectTimeout) {
      clearTimeout(this.reconnectTimeout)
    }
    if (this.ws) {
      this.ws.close()
      this.ws = null
    }
  }
}
```

**验收标准**：
- ✅ 网络断开后自动重连
- ✅ 最多重连 5 次，使用指数退避
- ✅ 心跳每 30 秒发送一次

