// src/dashboard/routes/iterations.ts

import { FastifyInstance } from 'fastify'

export async function iterationRoutes(fastify: FastifyInstance) {
  // 获取迭代列表（分页）
  fastify.get('/iterations', async (request, reply) => {
    const { page = 1, limit = 20, status } = request.query as any
    const iterationService = getServices().iterationService

    const iterations = await iterationService.list({
      page,
      limit,
      status
    })

    return iterations
  })

  // 获取迭代详情
  fastify.get('/iterations/:id', async (request, reply) => {
    const { id } = request.params as { id: string }
    const iterationService = getServices().iterationService

    const iteration = await iterationService.getById(Number(id))

    if (!iteration) {
      return reply.status(404).send({ error: 'Iteration not found' })
    }

    return iteration
  })

  // 获取当前运行迭代
  fastify.get('/iterations/current', async (request, reply) => {
    const iterationService = getServices().iterationService
    const currentIteration = await iterationService.getCurrent()

    return currentIteration || { status: 'idle' }
  })

  // 回滚到指定迭代
  fastify.post('/iterations/:id/rollback', async (request, reply) => {
    const { id } = request.params as { id: string }
    const iterationService = getServices().iterationService

    try {
      await iterationService.rollback(Number(id))
      return { success: true }
    } catch (error) {
      return reply.status(500).send({ error: 'Rollback failed' })
    }
  })
}
```

