## 🗄️ 五、数据库设计

### 5.1 数据库表结构

#### iterations 表

```sql
CREATE TABLE iterations (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  iteration_number INTEGER NOT NULL UNIQUE,
  requirement TEXT NOT NULL,
  status TEXT NOT NULL DEFAULT 'running',
  start_time INTEGER NOT NULL,
  end_time INTEGER,
  commit_hash TEXT,
  success BOOLEAN,
  error_message TEXT,
  created_at INTEGER NOT NULL DEFAULT (strftime('%s', 'now')),
  updated_at INTEGER NOT NULL DEFAULT (strftime('%s', 'now'))
);

CREATE INDEX idx_iterations_status ON iterations(status);
CREATE INDEX idx_iterations_number ON iterations(iteration_number);
```

#### agents 表

```sql
CREATE TABLE agents (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  name TEXT NOT NULL UNIQUE,
  status TEXT NOT NULL DEFAULT 'idle',
  current_task TEXT,
  last_execution_time INTEGER,
  total_tasks INTEGER DEFAULT 0,
  successful_tasks INTEGER DEFAULT 0,
  failed_tasks INTEGER DEFAULT 0,
  created_at INTEGER NOT NULL DEFAULT (strftime('%s', 'now')),
  updated_at INTEGER NOT NULL DEFAULT (strftime('%s', 'now'))
);
```

#### agent_execution_log 表

```sql
CREATE TABLE agent_execution_log (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  iteration_id INTEGER NOT NULL,
  agent_name TEXT NOT NULL,
  task TEXT NOT NULL,
  status TEXT NOT NULL,
  start_time INTEGER NOT NULL,
  end_time INTEGER,
  output TEXT,
  error TEXT,
  FOREIGN KEY (iteration_id) REFERENCES iterations(id) ON DELETE CASCADE
);

CREATE INDEX idx_agent_log_iteration ON agent_execution_log(iteration_id);
CREATE INDEX idx_agent_log_agent ON agent_execution_log(agent_name);
```

